import{_ as a,o as i,c as e,ai as n}from"./chunks/framework.CsYGeNYI.js";const c=JSON.parse('{"title":"OpenSoul 全方位指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide.md","filePath":"guide.md","lastUpdated":null}'),l={name:"guide.md"};function t(r,s,o,h,p,d){return i(),e("div",null,[...s[0]||(s[0]=[n('<h1 id="opensoul-全方位指南" tabindex="-1"><a class="header-anchor" href="#opensoul-全方位指南">#</a> OpenSoul 全方位指南</h1><p>本指南旨在为您提供 OpenSoul 项目的深度解析，涵盖方案设计、技术架构及详细的使用说明。无论您是初次接触的新用户，还是希望深入了解底层原理的开发者，都能在这里找到所需信息。</p><h2 id="_1-方案说明-scheme" tabindex="-1"><a class="header-anchor" href="#_1-方案说明-scheme">#</a> 1. 方案说明 (Scheme)</h2><h3 id="_1-1-应用场景与业务目标" tabindex="-1"><a class="header-anchor" href="#_1-1-应用场景与业务目标">#</a> 1.1 应用场景与业务目标</h3><p>OpenSoul 致力于构建一个<strong>永远在线的个人 AI 灵魂伴侣（Soul Companion）</strong>。它不仅仅是一个聊天机器人，更是一个能够深度集成到您日常生活中的智能代理。</p><ul><li><strong>核心场景</strong>： <ul><li><strong>多渠道统一接入</strong>：通过 WhatsApp、Telegram、Discord、Signal 等主流通讯软件与您的 AI 代理互动，无需切换应用。</li><li><strong>个人助理</strong>：AI 可以代表您执行本地命令、管理文件、查询信息，甚至通过 Home Assistant 控制智能家居。</li><li><strong>全天候陪伴</strong>：基于长期记忆（Memory）和个性化设定（Persona），AI 能够记住您的喜好、历史对话，提供更有温度的陪伴。</li></ul></li></ul><h3 id="_1-2-解决的问题" tabindex="-1"><a class="header-anchor" href="#_1-2-解决的问题">#</a> 1.2 解决的问题</h3><ul><li><strong>碎片化交互</strong>：解决了 AI 能力分散在不同 App 中的问题，通过统一网关（Gateway）聚合所有交互。</li><li><strong>隐私与控制</strong>：不同于云端 AI 服务，OpenSoul 强调<strong>本地优先</strong>。您的数据、记忆和执行逻辑运行在您控制的设备上（Local First）。</li><li><strong>执行力缺失</strong>：赋予 AI 实际的操作能力（Tools &amp; Skills），使其从“聊天”进化为“办事”。</li></ul><h3 id="_1-3-预期效果" tabindex="-1"><a class="header-anchor" href="#_1-3-预期效果">#</a> 1.3 预期效果</h3><p>构建一个属于您的高可定制、安全且强大的 AI 代理系统。它既是您的数字分身，也是您最得力的助手，能够跨越设备和平台，随时响应您的需求。</p><hr><h2 id="_2-技术实现-technical-implementation" tabindex="-1"><a class="header-anchor" href="#_2-技术实现-technical-implementation">#</a> 2. 技术实现 (Technical Implementation)</h2><h3 id="_2-1-技术架构" tabindex="-1"><a class="header-anchor" href="#_2-1-技术架构">#</a> 2.1 技术架构</h3><p>OpenSoul 采用中心化的 <strong>Gateway（网关）</strong> 架构，通过 WebSocket 协议连接各种客户端和节点。</p><ul><li><strong>核心组件</strong>： <ul><li><strong>Gateway (Daemon)</strong>：系统的核心心脏。负责维护与各消息平台（WhatsApp/Telegram 等）的连接，处理消息路由，并管理鉴权与安全性。</li><li><strong>Clients</strong>：控制平面客户端，包括 CLI 命令行工具、Web 控制台（Dashboard）和桌面应用。它们通过 WebSocket 连接网关进行管理和交互。</li><li><strong>Nodes</strong>：执行节点（macOS/iOS/Android/Headless）。这些节点也连接到网关，提供具体的设备能力（如摄像头、定位、屏幕录制等）。</li></ul></li></ul><h3 id="_2-2-关键技术选型" tabindex="-1"><a class="header-anchor" href="#_2-2-关键技术选型">#</a> 2.2 关键技术选型</h3><ul><li><strong>运行时</strong>：基于 <strong>Node.js (&gt;=22)</strong>，利用其强大的异步处理能力和丰富的生态系统。</li><li><strong>通信协议</strong>：<strong>WebSocket</strong>。保证了低延迟的双向通信，支持实时消息推送和流式传输（Streaming）。</li><li><strong>消息适配</strong>： <ul><li><strong>WhatsApp</strong>: 使用 <code>Baileys</code> 库实现无头协议接入。</li><li><strong>Telegram</strong>: 使用 <code>grammY</code> 框架构建高效 Bot。</li></ul></li><li><strong>数据存储</strong>：本地文件系统 + JSON/Markdown。采用人类可读的格式存储配置和记忆，方便备份与版本控制（Git）。</li></ul><h3 id="_2-3-核心机制" tabindex="-1"><a class="header-anchor" href="#_2-3-核心机制">#</a> 2.3 核心机制</h3><ul><li><strong>沙盒与安全 (Sandboxing)</strong>：默认情况下，外部会话运行在沙盒环境中，限制对宿主机的访问权限，确保安全。只有授权的主代理（Main Agent）才能执行敏感操作。</li><li><strong>设备配对 (Pairing)</strong>：采用基于设备 ID 的配对机制。所有连接网关的客户端都需要通过握手和签名验证，确保只有受信任的设备能接入网络。</li></ul><hr><h2 id="_3-使用指南-usage-guide" tabindex="-1"><a class="header-anchor" href="#_3-使用指南-usage-guide">#</a> 3. 使用指南 (Usage Guide)</h2><h3 id="_3-1-安装与配置" tabindex="-1"><a class="header-anchor" href="#_3-1-安装与配置">#</a> 3.1 安装与配置</h3><p>OpenSoul 支持 macOS、Linux 和 Windows (WSL2)。</p><p><strong>快速安装命令</strong>：</p><ul><li><p><strong>macOS / Linux</strong>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://opensoul.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Windows (PowerShell)</strong>:</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iwr </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">useb https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">opensoul.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><p><strong>初始化配置</strong>： 安装完成后，使用向导进行配置：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-daemon</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该向导将引导您完成：</p><ol><li>选择网关模式（本地/远程）。</li><li>配置 AI 模型提供商（如 Anthropic, OpenAI）。</li><li>接入消息渠道（WhatsApp, Telegram 等）。</li></ol><h3 id="_3-2-启动与运行" tabindex="-1"><a class="header-anchor" href="#_3-2-启动与运行">#</a> 3.2 启动与运行</h3><p>如果您在安装时选择了后台服务模式，OpenSoul 会自动运行。您可以通过以下命令检查状态：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>手动启动网关：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-3-功能使用" tabindex="-1"><a class="header-anchor" href="#_3-3-功能使用">#</a> 3.3 功能使用</h3><ul><li><p><strong>控制台 (Dashboard)</strong>： 运行 <code>opensoul dashboard</code> 打开 Web 管理界面，您可以在这里查看连接状态、管理会话和调试 AI 响应。</p></li><li><p><strong>双手机模式 (推荐)</strong>： 对于 WhatsApp 用户，建议准备一个专用手机号作为 AI 助理。使用您的主手机扫描 OpenSoul 生成的二维码，即可实现主号与 AI 助理的对话，避免消息混淆。</p></li><li><p><strong>工作区 (Workspace)</strong>： 您的 AI 代理的“大脑”位于 <code>~/.opensoul/workspace</code>。</p><ul><li><code>AGENTS.md</code>: 定义代理的人设和指令。</li><li><code>TOOLS.md</code>: 配置代理可使用的工具。</li><li>建议将此目录纳入 Git 版本控制，以备份您的个性化设置。</li></ul></li></ul><h3 id="_3-4-api-接口与开发" tabindex="-1"><a class="header-anchor" href="#_3-4-api-接口与开发">#</a> 3.4 API 接口与开发</h3><p>OpenSoul 提供了丰富的 API 供开发者扩展功能：</p><ul><li><strong>Gateway Protocol</strong>: 网关通信协议详解，请参考 <a href="/docs/gateway/protocol">Gateway Protocol</a>。</li><li><strong>OpenAI 兼容接口</strong>: 支持通过 OpenAI SDK 调用 OpenSoul，请参考 <a href="/docs/gateway/openai-http-api">OpenAI HTTP API</a>。</li><li><strong>插件开发</strong>: 了解如何编写插件，请参考 <a href="/docs/refactor/plugin-sdk">Plugin SDK</a>。</li></ul><h3 id="_3-5-常见问题-faq" tabindex="-1"><a class="header-anchor" href="#_3-5-常见问题-faq">#</a> 3.5 常见问题 (FAQ)</h3><ul><li><strong>Q: 如何重置配置？</strong> A: 使用 <code>opensoul reset</code> 命令可以重置网关配置。</li><li><strong>Q: 如何查看日志？</strong> A: 运行 <code>opensoul logs</code> 查看实时运行日志，有助于排查连接问题。</li></ul><p>更多详细文档请参考：</p><ul><li><a href="/docs/start/getting-started">快速开始</a></li><li><a href="/docs/concepts/architecture">架构详解</a></li><li><a href="/docs/install/index">安装指南</a></li></ul>',43)])])}const u=a(l,[["render",t]]);export{c as __pageData,u as default};
